query:
SELECT section, COUNT(*) as totale FROM news_items GROUP BY section;
SELECT section, COUNT(*) as url_specifici FROM news_items WHERE sourceUrl REGEXP '^https?://[^/]+/.+' GROUP BY section;
SELECT id, section, sourceName, LEFT(sourceUrl, 80) as sourceUrl FROM news_items WHERE sourceUrl REGEXP '^https?://[^/]+/.+' LIMIT 20;

